mapper.sql:
where audit.tenant_id = #{tenantId}
  and audit.del_flag = 0

  and audit.operation_result = #{operationResult}


  and (
    audit.operator_name like concat('%', #{keyword}, '%')
    or audit.operation_action like concat('%', #{keyword}, '%')
    or audit.resource_type like concat('%', #{keyword}, '%')
    or audit.resource_id like concat('%', #{keyword}, '%')
    or audit.operation_result like concat('%', #{keyword}, '%')
  )
